static std::atomic<CapturedTraceback::Python*> python_support_ = nullptr;

std::shared_ptr<CapturedTraceback> CapturedTraceback::gather(
    bool python,
    bool script,
    bool cpp) {
  auto r = std::make_shared<CapturedTraceback>();
  if (python) {
    auto p = python_support_.load();
    while (p && r->frames_.empty()) {
      // Check if it's safe to gather Python frames from current thread
      if (p->canGather()) {
        r->frames_ = p->gather();
        r->python_ = p;
      }
      p = p->next_;
    }
    // Try to gather forward traceback from current autograd node
    if (r->python_) {
      auto forward_tb = r->python_->gatherForwardTraceback();
      if (!forward_tb.empty()) {
        r->forward_traceback_ = std::move(forward_tb);
      }
    }
  }
  if (script) {
    r->script_frames_ = torch::jit::currentCallstack();
  }
  if (cpp) {
    r->cpp_frames_ = unwind::unwind();
  }
  return r;
}

