static inline unsigned char
hex2_to_uchar(const unsigned char *ptr, bool *badhex)
{
	unsigned char ret;
	signed char lookup;

	if (*ptr > 127)
		goto invalid_input;

	lookup = hexlookup[*ptr];
	if (lookup < 0)
		goto invalid_input;

	ret = lookup << 4;

	ptr++;

	if (*ptr > 127)
		goto invalid_input;

	lookup = hexlookup[*ptr];
	if (lookup < 0)
		goto invalid_input;

	ret += lookup;

	return ret;

invalid_input:
	*badhex = true;
	return 0;

