			verb := attr.GetVerb()
			sub := attr.GetSubresource()
			if verb == "get" && (sub == "" || sub == "dashboard") {
				return authorizer.DecisionAllow, "", nil
			}

			user, err := identity.GetRequester(ctx)
			if err != nil {
				return authorizer.DecisionDeny, "valid user is required", err
